package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author  string
	Content string
}

var comments = []Comment{
	{"Alice", "This is a great post!"},
	{"Bob", "<strong>Nice!</strong> I really enjoyed it."},
	{"Charlie", "Thanks for sharing!"},
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := template.Must(template.New("comments").Parse(`
		<!DOCTYPE html>
		<html>
		<head>
			<title>User Comments</title>
		</head>
		<body>
			<h1>User Comments</h1>
			<ul>
				{{range .}}
					<li><strong>{{.Author}}:</strong> {{.Content}}</li>
				{{end}}
			</ul>
		</body>
		</html>
	`))

	if err := tmpl.Execute(w, comments); err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}